import type { DynamicArea } from "../dynamic";
import type { TableNavBar } from "../table";

function updateNavBar(navBar: TableNavBar, page: number, params: { itemsPerPage: number; maxItems: number | null }) {
    const firstElementNumber = (page - 1) * params.itemsPerPage + 1;
    const lastElementNumber = Math.min(page * params.itemsPerPage, params.maxItems ?? Infinity);
    navBar.currentElementsNumber = `${firstElementNumber}..${lastElementNumber}`;
    navBar.isFirst = page === 1;
    navBar.isLast = params.maxItems !== null ? page >= Math.ceil(params.maxItems / params.itemsPerPage) : false;
}

function updateDynamicArea(area: DynamicArea, page: number, params: { urlTemplate: (page: number) => string }) {
    area.url = params.urlTemplate(page);
    void area.reload({soft: true});
}

function configureNavBar(navBar: TableNavBar, area: DynamicArea, params: { itemsPerPage: number; maxItems: number | null }) {
    navBar.useButtons = true;
    navBar.elementsCount = params.maxItems;
    navBar.empty = params.maxItems === 0;
    navBar.ariaControlsElements = [area];
}

function configureDynamicArea(area: DynamicArea) {
    area.autoload = false;
}

/**
 * Wire up pagination for a table. This function will set up the provided nav bars and dynamic area
 * to work together to provide server-side dynamic (AJAX) pagination functionality.
 *
 * @param params pagination parameters
 * @param params.currentPage the current page number (1-based)
 * @param params.itemsPerPage the number of items displayed per page
 * @param params.maxItems the total number of items (or null if unknown)
 * @param params.bars one or more TableNavBar elements to use for pagination controls
 * @param params.targetArea the DynamicArea to load paginated content into
 * @param params.urlTemplate a function that takes a page number and returns the URL to load that page
 */
export function pagination(
    params: {
        currentPage: number;
        itemsPerPage: number;
        maxItems: number | null;
        bars: TableNavBar | TableNavBar[];
        targetArea: DynamicArea;
        urlTemplate: (page: number) => string;
    }
): void {
    let currentPage = params.currentPage;
    const lastPage = params.maxItems !== null ? Math.ceil(params.maxItems / params.itemsPerPage) : null;
    const bars = Array.isArray(params.bars) ? params.bars : [params.bars];
    const targetArea = params.targetArea;
    configureDynamicArea(targetArea);
    updateDynamicArea(targetArea, currentPage, params);

    for (const bar of bars) {
        configureNavBar(bar, targetArea, params);
        updateNavBar(bar, currentPage, params);

        bar.addEventListener('table-nav-bar:click', e => {
            const button = e.detail.button;

            switch (button) {
                case 'first':
                    currentPage = 1;
                    break;
                case 'previous':
                    currentPage = Math.max(1, currentPage - 1);
                    break;
                case 'next':
                    currentPage = Math.min(lastPage ?? Infinity, currentPage + 1);
                    break;
                case 'last':
                    currentPage = lastPage ?? Infinity;
                    break;
            }

            updateDynamicArea(targetArea, currentPage, params);
            bars.forEach(bar => updateNavBar(bar, currentPage, params));
        });
    }
}
